Here's the code I recently added profiling to handle this. It should apply for 2.7 as well, but we were already using `execfile` so I didn't have to write it.

```python
if sys.version_info[0] >= 3:
    try:
        from tokenize import open as srcopen
    except ImportError:
        from io import TextIOWrapper
        from tokenize import detect_encoding

        def srcopen(filename):
            buff = open(filename, 'rb')
            try:
                encoding, lines = detect_encoding(buff.readline)
                buff.seek(0)
                if encoding == 'utf-8':
                    if next(iter(buff.read(1)), -1) == 0xEF:
                        encoding = 'utf-8-sig'
                    buff.seek(0)
                stream = TextIOWrapper(buff, encoding, line_buffering=True)
                stream.mode = 'r'
                return stream
            except:
                buff.close()
